  1→import { useState } from "react";
  2→import {
  3→  FileCode,
  4→  FilePlus,
  5→  FileMinus,
  6→  ChevronDown,
  7→  ChevronRight,
  8→  Loader2,
  9→  GitCommit,
 10→} from "lucide-react";
 11→import { useDiffQuery, useBranchDiffQuery } from "../../hooks/use-tauri-query";
 12→import type { CheckpointSummary, FileDiff, DiffLine as DiffLineType } from "../../lib/ipc";
 13→
 14→interface DiffViewProps {
 15→  repoPath: string;
 16→  checkpoint: CheckpointSummary | null;
 17→}
 18→
 19→const STATUS_CONFIG = {
 20→  added: { icon: FilePlus, color: "text-green", bg: "bg-green-bg", label: "Added" },
 21→  deleted: { icon: FileMinus, color: "text-red", bg: "bg-red-bg", label: "Deleted" },
 22→  modified: { icon: FileCode, color: "text-yellow", bg: "bg-yellow-bg", label: "Modified" },
 23→} as const;
 24→
 25→function DiffLineRow({ line }: { line: DiffLineType }) {
 26→  const isAdd = line.kind === "add";
 27→  const isDel = line.kind === "delete";
 28→
 29→  return (
 30→    <div
 31→      className="flex font-mono text-xs leading-[22px]"
 32→      style={{
 33→        backgroundColor: isAdd
 34→          ? "var(--color-diff-add-bg)"
 35→          : isDel
 36→            ? "var(--color-diff-delete-bg)"
 37→            : "transparent",
 38→      }}
 39→    >
 40→      {/* Old line number */}
 41→      <span
 42→        className="inline-block w-[50px] shrink-0 select-none border-r px-2 text-right text-[11px] leading-[22px] text-fg-subtle"
 43→        style={{
 44→          borderColor: "var(--color-border-subtle)",
 45→          backgroundColor: isDel
 46→            ? "var(--color-diff-delete-gutter)"
 47→            : isAdd
 48→              ? "var(--color-diff-add-gutter)"
 49→              : "transparent",
 50→        }}
 51→      >
 52→        {line.old_lineno ?? ""}
 53→      </span>
 54→      {/* New line number */}
 55→      <span
 56→        className="inline-block w-[50px] shrink-0 select-none border-r px-2 text-right text-[11px] leading-[22px] text-fg-subtle"
 57→        style={{
 58→          borderColor: "var(--color-border-subtle)",
 59→          backgroundColor: isAdd
 60→            ? "var(--color-diff-add-gutter)"
 61→            : isDel
 62→              ? "var(--color-diff-delete-gutter)"
 63→              : "transparent",
 64→        }}
 65→      >
 66→        {line.new_lineno ?? ""}
 67→      </span>
 68→      {/* +/- indicator */}
 69→      <span
 70→        className={`inline-block w-5 shrink-0 select-none text-center text-[11px] leading-[22px] ${
 71→          isAdd ? "text-green" : isDel ? "text-red" : "text-fg-faint"
 72→        }`}
 73→      >
 74→        {isAdd ? "+" : isDel ? "-" : " "}
 75→      </span>
 76→      {/* Code content */}
 77→      <pre
 78→        className={`min-w-0 flex-1 whitespace-pre-wrap break-all pr-4 ${
 79→          isAdd ? "text-green" : isDel ? "text-red" : "text-fg-muted"
 80→        }`}
 81→      >
 82→        {line.content}
 83→      </pre>
 84→    </div>
 85→  );
 86→}
 87→
 88→function FileEntry({
 89→  file,
 90→  defaultExpanded,
 91→}: {
 92→  file: FileDiff;
 93→  defaultExpanded: boolean;
 94→}) {
 95→  const [expanded, setExpanded] = useState(defaultExpanded);
 96→  const config = STATUS_CONFIG[file.status] || STATUS_CONFIG.modified;
 97→  const Icon = config.icon;
 98→
 99→  const additions = file.hunks.reduce(
100→    (sum, h) => sum + h.lines.filter((l) => l.kind === "add").length,
101→    0
102→  );
103→  const deletions = file.hunks.reduce(
104→    (sum, h) => sum + h.lines.filter((l) => l.kind === "delete").length,
105→    0
106→  );
107→
108→  return (
109→    <div className="mb-2 overflow-hidden rounded-lg border border-border-subtle">
110→      {/* File header */}
111→      <button
112→        onClick={() => setExpanded(!expanded)}
113→        className="flex w-full items-center gap-2 bg-bg-overlay px-3 py-2 text-left transition-colors hover:bg-bg-hover"
114→      >
115→        {expanded ? (
116→          <ChevronDown size={14} className="shrink-0 text-fg-subtle" />
117→        ) : (
118→          <ChevronRight size={14} className="shrink-0 text-fg-subtle" />
119→        )}
120→        <Icon size={14} className={`shrink-0 ${config.color}`} />
121→        <span className="min-w-0 flex-1 truncate font-mono text-xs text-fg">
122→          {file.path}
123→        </span>
124→        <span className={`shrink-0 rounded px-1.5 py-0.5 text-[10px] font-medium ${config.bg} ${config.color}`}>
125→          {config.label}
126→        </span>
127→        {additions > 0 && (
128→          <span className="shrink-0 font-mono text-[11px] text-green">
129→            +{additions}
130→          </span>
131→        )}
132→        {deletions > 0 && (
133→          <span className="shrink-0 font-mono text-[11px] text-red">
134→            -{deletions}
135→          </span>
136→        )}
137→      </button>
138→
139→      {/* Diff hunks */}
140→      {expanded && (
141→        <div className="overflow-x-auto border-t border-border-subtle bg-bg">
142→          {file.hunks.map((hunk, hi) => (
143→            <div key={hi}>
144→              {/* Hunk header */}
145→              <div
146→                className="border-b px-4 py-1 font-mono text-[11px]"
147→                style={{
148→                  backgroundColor: "var(--color-diff-hunk-bg)",
149→                  borderColor: "var(--color-border-subtle)",
150→                  color: "var(--color-accent-fg)",
151→                }}
152→              >
153→                {hunk.header.trim()}
154→              </div>
155→              {/* Lines */}
156→              <div>
157→                {hunk.lines.map((line, li) => (
158→                  <DiffLineRow key={li} line={line} />
159→                ))}
160→              </div>
161→            </div>
162→          ))}
163→          {file.hunks.length === 0 && (
164→            <div className="px-4 py-3 text-xs text-fg-subtle">
165→              Binary file or no textual changes
166→            </div>
167→          )}
168→        </div>
169→      )}
170→    </div>
171→  );
172→}
173→
174→function DiffFileList({
175→  files,
176→  summaryLabel,
177→  summaryDetail,
178→}: {
179→  files: FileDiff[];
180→  summaryLabel: string;
181→  summaryDetail?: string;
182→}) {
183→  const totalAdditions = files.reduce(
184→    (sum, f) =>
185→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "add").length, 0),
186→    0
187→  );
188→  const totalDeletions = files.reduce(
189→    (sum, f) =>
190→      sum + f.hunks.reduce((s, h) => s + h.lines.filter((l) => l.kind === "delete").length, 0),
191→    0
192→  );
193→
194→  return (
195→    <div className="px-5 py-4">
196→      <div className="mb-4 flex items-center gap-3 rounded-lg border border-border-subtle bg-bg-overlay px-4 py-3">
197→        <GitCommit size={14} className="text-fg-subtle" />
198→        <span className="font-mono text-xs text-fg-muted">{summaryLabel}</span>
199→        {summaryDetail && (
200→          <span className="text-xs text-fg-muted">{summaryDetail}</span>
201→        )}
202→        <div className="ml-auto flex items-center gap-3 text-xs">
203→          <span className="text-fg-subtle">{files.length} files</span>
204→          {totalAdditions > 0 && (
205→            <span className="font-mono text-green">+{totalAdditions}</span>
206→          )}
207→          {totalDeletions > 0 && (
208→            <span className="font-mono text-red">-{totalDeletions}</span>
209→          )}
210→        </div>
211→      </div>
212→      {files.map((file) => (
213→        <FileEntry
214→          key={file.path}
215→          file={file}
216→          defaultExpanded={files.length <= 5}
217→        />
218→      ))}
219→    </div>
220→  );
221→}
222→
223→export function DiffView({ repoPath, checkpoint }: DiffViewProps) {
224→  const { data: files, isLoading, error } = useDiffQuery(
225→    repoPath,
226→    checkpoint?.commit_sha ?? ""
227→  );
228→
229→  if (!checkpoint) {
230→    return (
231→      <div className="flex items-center justify-center p-20 text-fg-subtle">
232→        Select a checkpoint to view its diff
233→      </div>
234→    );
235→  }
236→
237→  if (!checkpoint.commit_sha) {
238→    return (
239→      <div className="p-8">
240→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
241→          <p className="text-sm text-fg-muted">No commit SHA available</p>
242→          <p className="mt-1 text-xs text-fg-subtle">
243→            This checkpoint's commit reference was not recorded
244→          </p>
245→          {checkpoint.files_touched.length > 0 && (
246→            <div className="mx-auto mt-4 max-w-md text-left">
247→              <p className="mb-2 text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
248→                Files touched
249→              </p>
250→              {checkpoint.files_touched.map((f) => (
251→                <div
252→                  key={f}
253→                  className="flex items-center gap-2 py-1 font-mono text-xs text-fg-muted"
254→                >
255→                  <FileCode size={12} className="shrink-0 text-fg-subtle" />
256→                  {f}
257→                </div>
258→              ))}
259→            </div>
260→          )}
261→        </div>
262→      </div>
263→    );
264→  }
265→
266→  if (isLoading) {
267→    return (
268→      <div className="flex items-center justify-center p-20">
269→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
270→      </div>
271→    );
272→  }
273→
274→  if (error) {
275→    return (
276→      <div className="p-8">
277→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
278→          <p className="text-sm text-fg-muted">Failed to load diff</p>
279→          <p className="mt-1 text-xs text-fg-subtle">
280→            {error instanceof Error ? error.message : "Unknown error"}
281→          </p>
282→        </div>
283→      </div>
284→    );
285→  }
286→
287→  if (!files || files.length === 0) {
288→    return (
289→      <div className="p-8">
290→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
291→          <p className="text-sm text-fg-muted">No changes in this commit</p>
292→        </div>
293→      </div>
294→    );
295→  }
296→
297→  return (
298→    <DiffFileList
299→      files={files}
300→      summaryLabel={checkpoint.commit_sha.slice(0, 7)}
301→      summaryDetail={checkpoint.commit_message || "Untitled commit"}
302→    />
303→  );
304→}
