 1→import { useEffect, useRef } from "react";
 2→import { listen, type UnlistenFn } from "@tauri-apps/api/event";
 3→
 4→export function useTauriEvent<T>(
 5→  event: string,
 6→  callback: (payload: T) => void
 7→) {
 8→  const callbackRef = useRef(callback);
 9→  callbackRef.current = callback;
10→
11→  useEffect(() => {
12→    let unlisten: UnlistenFn | undefined;
13→
14→    listen<T>(event, (e) => {
15→      callbackRef.current(e.payload);
16→    }).then((fn) => {
17→      unlisten = fn;
18→    });
19→
20→    return () => {
21→      unlisten?.();
22→    };
23→  }, [event]);
24→}
