import { useState, useCallback, useMemo, useEffect } from "react";

export interface DiffComment {
  id: string;
  filePath: string;
  lineKey: string; // "{filePath}:{old_lineno}:{new_lineno}"
  lineKind: "add" | "delete" | "context";
  lineContent: string;
  lineNumber: number;
  comment: string;
  createdAt: number;
}

function loadComments(storageKey: string): DiffComment[] {
  try {
    const raw = localStorage.getItem(storageKey);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

function saveComments(storageKey: string, comments: DiffComment[]) {
  if (comments.length === 0) {
    localStorage.removeItem(storageKey);
  } else {
    localStorage.setItem(storageKey, JSON.stringify(comments));
  }
}

export function useDiffComments(storageKey: string) {
  const [comments, setComments] = useState<DiffComment[]>(() =>
    loadComments(storageKey)
  );

  // Re-load when storageKey changes
  useEffect(() => {
    setComments(loadComments(storageKey));
  }, [storageKey]);

  // Persist on every change
  useEffect(() => {
    saveComments(storageKey, comments);
  }, [storageKey, comments]);

  const commentsByLine = useMemo(() => {
    const map = new Map<string, DiffComment[]>();
    for (const c of comments) {
      const existing = map.get(c.lineKey);
      if (existing) {
        existing.push(c);
      } else {
        map.set(c.lineKey, [c]);
      }
    }
    return map;
  }, [comments]);

  const addComment = useCallback(
    (
      filePath: string,
      lineKey: string,
      lineKind: "add" | "delete" | "context",
      lineContent: string,
      lineNumber: number,
      comment: string
    ) => {
      const newComment: DiffComment = {
        id: crypto.randomUUID(),
        filePath,
        lineKey,
        lineKind,
        lineContent,
        lineNumber,
        comment,
        createdAt: Date.now(),
      };
      setComments((prev) => [...prev, newComment]);
    },
    []
  );

  const updateComment = useCallback((id: string, comment: string) => {
    setComments((prev) =>
      prev.map((c) => (c.id === id ? { ...c, comment } : c))
    );
  }, []);

  const deleteComment = useCallback((id: string) => {
    setComments((prev) => prev.filter((c) => c.id !== id));
  }, []);

  const clearAll = useCallback(() => {
    setComments([]);
  }, []);

  return { comments, commentsByLine, addComment, updateComment, deleteComment, clearAll };
}

