import { useState, useCallback, useImperativeHandle, forwardRef } from "react";
import { invoke } from "@tauri-apps/api/core";
import { XTerminal } from "./XTerminal";
import type { Tab } from "../../App";

export interface TerminalPanelHandle {
  launchAgentWithPrompt: (agent: string, prompt: string) => Promise<void>;
}

interface TerminalPanelProps {
  height: number;
  tab: Tab;
  onToggle: () => void;
}

interface TermSession {
  id: string;
  agent: string;
  label: string;
}

export const TerminalPanel = forwardRef<TerminalPanelHandle, TerminalPanelProps>(
  function TerminalPanel({ height, tab, onToggle }, ref) {
  const [sessions, setSessions] = useState<TermSession[]>([]);
  const [activeSessionIdx, setActiveSessionIdx] = useState(0);

  const activeSession = sessions[activeSessionIdx] ?? null;

  const launchAgent = useCallback(
    async (agent: string) => {
      if (!tab.repoPath) {
        console.warn("No repo path set — cannot launch agent");
        return "";
      }
      try {
        const sessionId: string = await invoke("spawn_agent", {
          repoPath: tab.repoPath,
          agent,
        });
        const newSession: TermSession = {
          id: sessionId,
          agent,
          label: `${agent === "claude-code" ? "Claude Code" : "Codex"} — ${tab.branch}`,
        };
        setSessions((prev) => [...prev, newSession]);
        setActiveSessionIdx(sessions.length);
        return sessionId;
      } catch (err) {
        console.error("Failed to spawn agent:", err);
        return "";
      }
    },
    [tab.repoPath, tab.branch, sessions.length]
  );

  useImperativeHandle(ref, () => ({
    async launchAgentWithPrompt(agent: string, prompt: string) {
      const sessionId = await launchAgent(agent);
      if (!sessionId) return;
      // Small delay for PTY initialization before sending input
      setTimeout(async () => {
        try {
          await invoke("pty_input", { sessionId, data: prompt + "\n" });
        } catch (err) {
          console.error("Failed to send prompt to agent:", err);
        }
      }, 150);
    },
  }), [launchAgent]);

  return (
    <div className="flex shrink-0 flex-col bg-[#0a0a0a]" style={{ height }}>
      {/* Terminal header with session tabs */}
      <div className="flex items-center gap-2 border-t border-border bg-bg-raised px-3 py-1.5">
        {sessions.map((session, idx) => (
          <button
            key={session.id}
            onClick={() => setActiveSessionIdx(idx)}
            className={`flex items-center gap-1.5 rounded-md px-2.5 py-1 text-[11px] ${
              idx === activeSessionIdx
                ? "bg-accent-bg text-accent-fg"
                : "text-fg-subtle hover:bg-bg-hover"
            }`}
          >
            <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-green" />
            {session.label}
          </button>
        ))}

        {sessions.length === 0 && (
          <>
            <button
              onClick={() => launchAgent("claude-code")}
              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-accent hover:text-accent-fg"
            >
              + Claude Code
            </button>
            <button
              onClick={() => launchAgent("codex")}
              className="flex items-center gap-1.5 rounded-md border border-border-subtle px-2.5 py-1 text-[11px] text-fg-subtle transition-colors hover:border-green hover:text-green"
            >
              + Codex
            </button>
          </>
        )}

        {sessions.length > 0 && (
          <button
            onClick={() => {
              // Quick launch menu — cycle agents
              const nextAgent =
                sessions[sessions.length - 1]?.agent === "claude-code"
                  ? "codex"
                  : "claude-code";
              launchAgent(nextAgent);
            }}
            className="rounded-md px-2 py-1 text-[11px] text-fg-subtle hover:bg-bg-hover"
          >
            +
          </button>
        )}

        <button
          onClick={onToggle}
          className="ml-auto px-2 py-1 text-[11px] text-fg-subtle hover:text-fg-muted"
        >
          ⌃` Toggle ▾
        </button>
      </div>

      {/* Terminal body */}
      <div className="flex-1 overflow-hidden">
        <XTerminal sessionId={activeSession?.id ?? null} />
      </div>
    </div>
  );
});

