  2→import { Terminal } from "@xterm/xterm";
  3→import { FitAddon } from "@xterm/addon-fit";
  4→import { invoke } from "@tauri-apps/api/core";
  5→import { useTauriEvent } from "../../hooks/use-tauri-event";
  6→import "@xterm/xterm/css/xterm.css";
  7→
  8→interface XTerminalProps {
  9→  sessionId: string | null;
 10→  className?: string;
 11→}
 12→
 13→export function XTerminal({ sessionId, className }: XTerminalProps) {
 14→  const containerRef = useRef<HTMLDivElement>(null);
 15→  const termRef = useRef<Terminal | null>(null);
 16→  const fitAddonRef = useRef<FitAddon | null>(null);
 17→
 18→  // Handle PTY output from Rust backend
 19→  useTauriEvent<{ sessionId: string; data: number[] }>(
 20→    "pty-output",
 21→    useCallback(
 22→      (payload) => {
 23→        if (payload.sessionId === sessionId && termRef.current) {
 24→          const bytes = new Uint8Array(payload.data);
 25→          termRef.current.write(bytes);
 26→        }
 27→      },
 28→      [sessionId]
 29→    )
 30→  );
 31→
 32→  useEffect(() => {
 33→    if (!containerRef.current) return;
 34→
 35→    const term = new Terminal({
 36→      fontFamily: "'SF Mono', 'Fira Code', 'Cascadia Code', monospace",
 37→      fontSize: 13,
 38→      lineHeight: 1.5,
 39→      cursorBlink: true,
 40→      cursorStyle: "block",
 41→      theme: {
 42→        background: "#0a0a0a",
 43→        foreground: "#e4e4e7",
 44→        cursor: "#7c3aed",
 45→        cursorAccent: "#0a0a0a",
 46→        selectionBackground: "#7c3aed44",
 47→        black: "#0d0d0d",
 48→        red: "#f87171",
 49→        green: "#4ade80",
 50→        yellow: "#fbbf24",
 51→        blue: "#60a5fa",
 52→        magenta: "#a78bfa",
 53→        cyan: "#22d3ee",
 54→        white: "#e4e4e7",
 55→        brightBlack: "#555555",
 56→        brightRed: "#fca5a5",
 57→        brightGreen: "#86efac",
 58→        brightYellow: "#fde68a",
 59→        brightBlue: "#93c5fd",
 60→        brightMagenta: "#c4b5fd",
 61→        brightCyan: "#67e8f9",
 62→        brightWhite: "#ffffff",
 63→      },
 64→    });
 65→
 66→    const fitAddon = new FitAddon();
 67→    term.loadAddon(fitAddon);
 68→    term.open(containerRef.current);
 69→
 70→    // Fit after a small delay to ensure container has dimensions
 71→    requestAnimationFrame(() => {
 72→      fitAddon.fit();
 73→    });
 74→
 75→    // Send user input to PTY
 76→    term.onData((data) => {
 77→      if (sessionId) {
 78→        invoke("pty_input", { sessionId, data }).catch(console.error);
 79→      }
 80→    });
 81→
 82→    // Resize PTY when terminal resizes
 83→    term.onResize(({ cols, rows }) => {
 84→      if (sessionId) {
 85→        invoke("pty_resize", { sessionId, cols, rows }).catch(console.error);
 86→      }
 87→    });
 88→
 89→    termRef.current = term;
 90→    fitAddonRef.current = fitAddon;
 91→
 92→    // Handle window resize
 93→    const resizeObserver = new ResizeObserver(() => {
 94→      requestAnimationFrame(() => {
 95→        fitAddon.fit();
 96→      });
 97→    });
 98→    resizeObserver.observe(containerRef.current);
 99→
100→    // Welcome message if no session
101→    if (!sessionId) {
102→      term.writeln("\x1b[38;2;124;58;237m");
103→      term.writeln("  ╔═══════════════════════════════════╗");
104→      term.writeln("  ║         Entire Desktop            ║");
105→      term.writeln("  ║                                   ║");
106→      term.writeln("  ║  Click 'New Session' to start     ║");
107→      term.writeln("  ║  a Claude Code or Codex session   ║");
108→      term.writeln("  ╚═══════════════════════════════════╝");
109→      term.writeln("\x1b[0m");
110→    }
111→
112→    return () => {
113→      resizeObserver.disconnect();
114→      term.dispose();
115→      termRef.current = null;
116→      fitAddonRef.current = null;
117→    };
118→  }, [sessionId]);
119→
120→  return (
121→    <div
122→      ref={containerRef}
123→      className={`h-full w-full ${className ?? ""}`}
124→      style={{ padding: "4px 8px" }}
125→    />
126→  );
127→}
