286→#[tauri::command]
287→fn get_branch_diff(
288→    repo_path: String,
289→    branch: String,
290→) -> Result<Vec<FileDiff>, String> {
291→    let repo = git::open_repo(&repo_path)?;
292→
293→    // Resolve the branch HEAD
294→    let branch_ref = repo
295→        .find_branch(&branch, git2::BranchType::Local)
296→        .map_err(|e| format!("Branch not found: {}", e))?;
297→    let branch_commit = branch_ref
298→        .get()
299→        .peel_to_commit()
300→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
301→
302→    // Find the default branch (try main, then master)
303→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
304→        "main"
305→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
306→        "master"
307→    } else {
308→        return Err("No default branch (main/master) found".to_string());
309→    };
310→
311→    // If we're diffing the default branch against itself, return empty
312→    if branch == default_branch_name {
313→        return Ok(Vec::new());
314→    }
315→
316→    let default_ref = repo
317→        .find_branch(default_branch_name, git2::BranchType::Local)
318→        .map_err(|e| format!("Default branch error: {}", e))?;
319→    let default_commit = default_ref
320→        .get()
321→        .peel_to_commit()
322→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
323→
324→    // Find merge base
325→    let merge_base_oid = repo
326→        .merge_base(default_commit.id(), branch_commit.id())
327→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
328→    let merge_base_commit = repo
329→        .find_commit(merge_base_oid)
330→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
331→
332→    let base_tree = merge_base_commit
333→        .tree()
334→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
335→    let branch_tree = branch_commit
336→        .tree()
337→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
338→
339→    let diff = repo
340→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
341→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
342→
343→    collect_diff_files(&diff)
344→}
